import{kn as e}from"./chunk-IjxM6APl.js";var t=e(),n={publishing_date:`2025-05-26`,title:`Updates to the website`,tokenID:26,category:`webdev`,description:`I explore my website's evolution over 6 months, from minimal CSS to Panda CSS and Copilot refactoring. See how modern tools dramatically boost development productivity.`};function r(e){let n={a:`a`,blockquote:`blockquote`,code:`code`,h2:`h2`,li:`li`,p:`p`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.p,{children:`It has been roughly 6 months since I started this website. All in all, it is a enjoyable experience to have this super flexible stack on which I can simply play around in the way I want. So it is time to summarize the most important changes and updates on the stack over the last few months.`}),`
`,(0,t.jsx)(n.h2,{children:`Panda CSS for consistent styling`}),`
`,(0,t.jsxs)(n.p,{children:[`At the beginning, I kept the styling super minimalistic and just used inline css. This was ok at the beginning but by the time that I started to add the lecture notes and the image generator it become quite cumbersome to work in this way. So I started to look for a proper CSS solution. I wanted something that is simple, flexible and does not require a lot of setup. After some research, I settled on `,(0,t.jsx)(n.a,{href:`https://panda-css.com/`,children:`Panda CSS`}),`. It allows me to write CSS in a very JS-like way, which is very convenient. It also has a great integration with Vike and works well with the rest of the stack. All in all, there will be no looking back.`]}),`
`,(0,t.jsx)(n.h2,{children:`Copilot for code refactoring`}),`
`,(0,t.jsxs)(n.p,{children:[`In the middle of the refactoring, I also made my first experiences with the `,(0,t.jsx)(n.a,{href:`https://github.blog/ai-and-ml/github-copilot/agent-mode-101-all-about-github-copilots-powerful-mode/`,children:`Copilot Agent Mode`}),`. Previously, I had only used Copilot in the normal way, i.e. it would suggest code snippets as I was typing. However, with the Agent Mode, I can now let Copilot refactor my code in a much more comprehensive way. I only gave the following instruction:`]}),`
`,(0,t.jsxs)(n.blockquote,{children:[`
`,(0,t.jsxs)(n.p,{children:[`The code within the website folder uses pandacss. However in a lot of the components and pages similiar styles are defined independently and hence not consistent. The code should have all the style definitions in a consistent way in the `,(0,t.jsx)(n.code,{children:`styles.ts`}),` file.`]}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`Then I let Copilot run with `,(0,t.jsx)(n.a,{href:`https://www.anthropic.com/claude/sonnet`,children:`Sonnet 4`}),` for about 20 minutes. Quite amazingly, it did a remarkable job involving fifteen files and hundreds of lines of code. All I had to do was a lint fix and `,(0,t.jsx)(n.a,{href:`https://github.com/fretchen/fretchen.github.io/commit/8b9f37cb0ce2ef54bed23b034a40cebde72608b4`,children:`that's it`}),`. This really makes you wonder which projects are now possible that I put on the backburner before because they were just to long and not fun enough.`]}),`
`,(0,t.jsx)(n.h2,{children:`More lecture notes`}),`
`,(0,t.jsxs)(n.p,{children:[`I was now able to move a number of lecture notes into the new `,(0,t.jsx)(n.a,{href:`../quantum`,children:`quantum`}),` section. It was all in all a rather straightforward process. I just had to convert the jupyter notebooks to markdown and then add them to the website. With the new content it actually became clear that the file based structure of content is a bit cumbersome. Yes, I previously started a new folder on each project. However, with the blog it would feel tempting to have a single stream of files, which are later sorted by tags etc into different views.`]}),`
`,(0,t.jsx)(n.h2,{children:`A quick outlook`}),`
`,(0,t.jsx)(n.p,{children:`We will see where it takes me from here but a number of things could be cool:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`An image gallery for the generator that allows to browse the images, search for them and burn them if you feel like it. Maybe even have a functionality that automatically burns the images after a certain time if you don't want to keep them explicitly ?`}),`
`,(0,t.jsx)(n.li,{children:`Introducing more tags etc to the blog to get a simpler handle on the content. Maybe I will be able to get rid of the folder structure and just have a single stream of content.`}),`
`,(0,t.jsx)(n.li,{children:`On the more ambitious side, I really start to wonder if I can finally get quantum onto the blockchain. I had some thoughts on this, I think that it is possible, but I have to find the motivation to get started on it.`}),`
`]})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};